// build.gradle (Module: app)
dependencies {
    implementation 'com.squareup.retrofit2:retrofit:2.9.0'
    implementation 'com.squareup.retrofit2:converter-gson:2.9.0'
    implementation 'com.squareup.okhttp3:okhttp:4.9.0'
    implementation 'com.squareup.okhttp3:logging-interceptor:4.9.0'
}

// ApiService.kt
interface ApiService {
    @GET("users")
    suspend fun getUserProfiles(): Response<List<UserProfile>>
}

// NetworkModule.kt
object NetworkModule {
    private const val DEV_BASE_URL = "https://dev.api.example.com/"
    private const val STAGING_BASE_URL = "https://staging.api.example.com/"
    private const val PROD_BASE_URL = "https://api.example.com/"

    private fun getBaseUrl(): String {
        return when (BuildConfig.BUILD_TYPE) {
            "debug" -> DEV_BASE_URL
            "staging" -> STAGING_BASE_URL
            else -> PROD_BASE_URL
        }
    }

    private fun getOkHttpClient(authToken: String): OkHttpClient {
        val logging = HttpLoggingInterceptor()
        logging.setLevel(HttpLoggingInterceptor.Level.BODY)
        
        return OkHttpClient.Builder()
            .addInterceptor(logging)
            .addInterceptor { chain ->
                val request = chain.request().newBuilder()
                    .addHeader("Authorization", "Bearer $authToken")
                    .build()
                chain.proceed(request)
            }
            .build()
    }

    fun createApiService(authToken: String): ApiService {
        val retrofit = Retrofit.Builder()
            .baseUrl(getBaseUrl())
            .client(getOkHttpClient(authToken))
            .addConverterFactory(GsonConverterFactory.create())
            .build()
        
        return retrofit.create(ApiService::class.java)
    }
}

// UserProfile.kt
data class UserProfile(
    val id: String,
    val name: String,
    val email: String
)

